素材が一皿に表れる。", "source_urls": ["https://en.wikipedia.org/wiki/Doubles_(food)"], "is_vegan": true, "is_gluten_free": false}, {"source_ref": "research:conch-fritters", "title": "Conch fritters", "description": "Conch frittersは、バハマ / バハマ料理を代表する実在の料理として知られ、コンク貝を中心に地域の食材と調理法を組み合わせる一皿です。", "cuisine": "バハマ / バハマ料理", "flag": "🇧🇸", "image_url": "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800", "cook_time_min": 25, "servings": 4, "tags": ["実データ", "Web調査", "出典あり", "バハマ"], "steps": [{"order": 1, "text": "コンク貝と小麦粉を下ごしらえし、香味野菜や調味料で味の土台を作ります。"}, {"order": 2, "text": "残りの具材を合わせて火を通し、現地の食べ方に近い形で盛り付けます。"}], "ingredients": ["コンク貝", "小麦粉", "玉ねぎ", "ピーマン", "唐辛子"], "origin_title": "Conch fritters の由来", "origin_body": "Conch frittersはバハマの食卓で食べ継がれてきた料理で、出典URLに示した資料でも地域料理として確認できます。現在の形は、コンク貝や小麦粉など身近な素材、交易・移民・家庭調理の積み重ねの中で整いました。", "culture_title": "バハマの食文化と宗教の影響", "culture_body": "先住民、アフリカ系、ヨーロッパ系、移民コミュニティの食文化が重なり、宗教儀礼や祝祭、屋台文化と結びつくことが多い。共同体の記憶と海・畑の素材が一皿に表れる。", "source_urls": ["https://www.bahamas.com/plan-your-trip/restaurants/fish-fry-arawak-cay", "https://en.wikipedia.org/wiki/Conch"], "is_vegan": false, "is_gluten_free": false}]$global_dishes$::jsonb) as d(
  source_ref text,
  title text,
  description text,
  cuisine text,
  flag text,
  image_url text,
  cook_time_min int,
  servings int,
  tags jsonb,
  steps jsonb,
  ingredients jsonb,
  origin_title text,
  origin_body text,
  culture_title text,
  culture_body text,
  source_urls jsonb,
  is_vegan boolean,
  is_gluten_free boolean
);

-- User-owned recipes are preserved. Only earlier demo/mock API seeds and this managed research seed are replaced.
delete from public.recipes
where source_type = 'api'
  and (source_ref like 'mock:rec-%' or source_ref like 'research:%');

insert into public.recipes (
  source_type,
  source_ref,
  title,
  description,
  cuisine,
  flag,
  image_url,
  cook_time_min,
  servings,
  is_public,
  is_vegan,
  is_gluten_free,
  tags,
  steps
)
select
  'api',
  source_ref,
  title,
  description,
  cuisine,
  flag,
  image_url,
  cook_time_min,
  servings,
  true,
  is_vegan,
  is_gluten_free,
  array(select jsonb_array_elements_text(tags)),
  steps
from _global_dish_seed
on conflict (source_type, source_ref) where source_ref is not null do update set
  title = excluded.title,
  description = excluded.description,
  cuisine = excluded.cuisine,
  flag = excluded.flag,
  image_url = excluded.image_url,
  cook_time_min = excluded.cook_time_min,
  servings = excluded.servings,
  is_public = excluded.is_public,
  is_vegan = excluded.is_vegan,
  is_gluten_free = excluded.is_gluten_free,
  tags = excluded.tags,
  steps = excluded.steps;

with ingredient_seed as (
  select distinct
    d.source_ref || ':ingredient:' || lpad(i.ordinality::text, 2, '0') as name_en,
    i.ingredient as name_ja
  from _global_dish_seed d
  cross join lateral jsonb_array_elements_text(d.ingredients) with ordinality as i(ingredient, ordinality)
)
insert into public.ingredients (name_ja, name_en, category)
select name_ja, name_en, '世界料理'
from ingredient_seed
on conflict (name_en) do update set
  name_ja = excluded.name_ja,
  category = excluded.category;

with ingredient_seed as (
  select
    d.source_ref,
    d.source_ref || ':ingredient:' || lpad(i.ordinality::text, 2, '0') as name_en,
    i.ordinality
  from _global_dish_seed d
  cross join lateral jsonb_array_elements_text(d.ingredients) with ordinality as i(ingredient, ordinality)
)
insert into public.recipe_ingredients (recipe_id, ingredient_id, quantity, is_optional)
select r.id, ing.id, '適量', false
from ingredient_seed s
join public.recipes r
  on r.source_type = 'api'
 and r.source_ref = s.source_ref
join public.ingredients ing
  on ing.name_en = s.name_en
on conflict (recipe_id, ingredient_id) do update set
  quantity = excluded.quantity,
  is_optional = excluded.is_optional;

with culture_seed as (
  select source_ref, 'origin'::text as section_key, '由来'::text as label, origin_title as title, origin_body as body, 1 as sort_order
  from _global_dish_seed
  union all
  select source_ref, 'food_culture'::text, '食文化'::text, culture_title, culture_body, 2
  from _global_dish_seed
)
insert into public.recipe_culture_sections (recipe_id, section_key, label, title, body, sort_order)
select r.id, c.section_key, c.label, c.title, c.body, c.sort_order
from culture_seed c
join public.recipes r
  on r.source_type = 'api'
 and r.source_ref = c.source_ref
on conflict (recipe_id, section_key) do update set
  label = excluded.label,
  title = excluded.title,
  body = excluded.body,
  sort_order = excluded.sort_order,
  updated_at = now();

with source_seed as (
  select d.source_ref, url.source_url, null::text as source_title
  from _global_dish_seed d
  cross join lateral jsonb_array_elements_text(d.source_urls) as url(source_url)
)
insert into public.recipe_research_sources (recipe_id, source_url, source_title)
select r.id, s.source_url, s.source_title
from source_seed s
join public.recipes r
  on r.source_type = 'api'
 and r.source_ref = s.source_ref
on conflict (recipe_id, source_url) do update set
  source_title = excluded.source_title;
